dict_type_id = #{dictTypeId}, label = #{label}, value = #{value}, sort = #{sort}, css_class = #{cssClass}, list_class = #{listClass}, default_flag = #{defaultFlag, typeHandler=com.soli.common.core.mybatis.handler.DbEnumTypeHandler}, status = #{status, typeHandler=com.soli.common.core.mybatis.handler.DbEnumTypeHandler}, update_by = #{updateBy}, update_time = #{updateTime}, note = #{note},
where id = #{id}

update sys_dict_data
set default_flag = 'N'
where dict_type_id = #{dictTypeId}
  and default_flag = 'Y'

  and id != #{excludeId}

mapper.select:
select from sys_dict_data
and dict_type_id = #{dictTypeId}
and label like concat('%', #{label}, '%')
and value like concat('%', #{value}, '%')
and status = #{status, typeHandler=com.soli.common.core.mybatis.handler.DbEnumTypeHandler}
order by sort asc, id desc
